<template>
  <div class="chart" />
</template>
<script>
import * as echarts from "echarts";
export default {
  name: "ChartLine",
  props: {
    seriesData: {
      type: Object,
      required: true,
      default: () => {},
    },
  },
  data() {
    return {
      chart: null,
    };
  },
  computed: {},
  watch: {
    // 监听数据变化
    seriesData: {
      deep: true,
      handler() {
        this.updateChartView();
      },
    },
  },
  mounted() {
    this.chart = echarts.init(this.$el);
    this.updateChartView();
    window.addEventListener("resize", this.handleWindowResize);
  },
  beforeDestroy() {
    window.removeEventListener("resize", this.handleWindowResize);
  },
  methods: {
    // chart样式
    assembleDataToOption(xData, yData) {
      return {
        tooltip: {
          confine: true,
          trigger: "axis",
        },
        legend: {
          show: false,
        },
        xAxis: {
          axisLabel: {
            show: true,
            color: "rgba(255,255,255,0.6)",
          },
          axisTick: {
            show: false,
          },
          splitLine: {
            show: false,
          },
          axisLine: {
            show: true,
            lineStyle: {
              color: "rgba(255,255,255,0.6)",
            },
          },
          data: xData,
          type: "category",
          boundaryGap: false,
        },
        yAxis: {
          type: "value",
          axisLabel: {
            show: true,
            color: "rgba(255,255,255,0.6)",
          },
          axisTick: {
            show: false,
          },
          splitLine: {
            show: false,
          },
          axisLine: {
            show: false,
          },
        },
        grid: {
          containLabel: true,
          left: 0,
          right: 12,
          bottom: 0,
          top: 20,
        },
        series: [
          {
            type: "line",
            smooth: true,
            showSymbol: false,
            areaStyle: {
              opacity: 0.8,
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
                {
                  offset: 0,
                  color: "rgb(180, 106,30,0.8)",
                },
                {
                  offset: 1,
                  color: "rgb(180, 106,30,0.1)",
                },
              ]),
            },
            emphasis: {
              focus: "series",
            },
            itemStyle: {
              normal: {
                color: "#fb8d1c",
              },
            },
            data: yData,
          },
        ],
      };
    },
    // chart数据挂载
    updateChartView() {
      if (!this.chart) return;
      const fullOption = this.assembleDataToOption(
        this.seriesData.xData,
        this.seriesData.yData
      );
      this.chart.setOption(fullOption, true);
    },
    // chart自适应
    handleWindowResize() {
      if (!this.chart) return;
      this.chart.resize();
    },
  },
};
</script>
<style lang="scss" scoped>
.chart {
  width: 100%;
  height: 100%;
}
</style>
