import Vue from "vue";
import VueRouter from "vue-router";
import IndexView from "../views/IndexView.vue";
import DemoView from "../views/demoView.vue";
Vue.use(VueRouter);

const routes = [
  { path: "/", redirect: "/index" },
  {
    path: "/index",
    name: "index",
    component: IndexView,
  },
  {
    path: "/demo",
    name: "demo",
    component: DemoView,
  },
];

const router = new VueRouter({
  routes,
});

export default router;
