<template>
  <div class="tabList">
    <ul>
      <li
        v-for="(item, index) in data"
        :key="index"
        :class="tabIndex == index ? 'active' : ''"
        @click="tab(index)"
      >
        <p>
          <img :src="require('@/assets/images/' + item.icon + '.png')" alt="" />
          <span>{{ item.name }}</span>
        </p>
        <p class="value">{{ item.value }}</p>
      </li>
    </ul>
  </div>
</template>
<script>
export default {
  name: "TabList",
  data() {
    return {
      tabIndex: 0,
    };
  },
  props: {
    data: {
      type: Array,
      required: true,
      default: () => [],
    },
  },
  components: {},
  mounted() {},
  methods: {
    tab(index) {
      this.tabIndex = index;
      this.$emit("changeOrderType", index);
    },
  },
};
</script>
