    },
    // 鼠标离开
    mouseLeave1() {
      this.autoPlay1 = true;
    },
    mouseLeave2() {
      this.autoPlay2 = true;
    },
    startMove() {
      // 拿到表格挂载后的真实DOM
      const table1 = this.$refs.scroll_table1;
      const table2 = this.$refs.scroll_table2;
      if (table1) {
        // 拿到表格中承载数据的div元素
        const divData = table1.bodyWrapper;
        if (divData) {
          if (this.timer1) {
            clearInterval(this.timer1);
          }
          // 拿到元素后，对元素进行定时增加距离顶部距离，实现滚动效果(此配置为每20毫秒移动1像素)
          this.timer1 = setInterval(() => {
            if (this.autoPlay1) {
              divData.scrollTop += 1;
              // 元素自增距离顶部1像素
              if (divData.scrollTop >= 36) {
                const item = this.personnelTableData.shift();
                this.personnelTableData.push(item);
                divData.scrollTop = 0;
              }
            }
          }, 40);
        }
      }
      if (table2) {
        // 拿到表格中承载数据的div元素
        const divData = table2.bodyWrapper;
        if (divData) {
          if (this.timer2) {
            clearInterval(this.timer2);
          }
          // 拿到元素后，对元素进行定时增加距离顶部距离，实现滚动效果(此配置为每20毫秒移动1像素)
