            if (this.autoPlay2) {
              divData.scrollTop += 1;
              // 元素自增距离顶部1像素
              if (divData.scrollTop >= 36) {
                const item = this.orderTableData.shift();
                this.orderTableData.push(item);
                divData.scrollTop = 0;
              }
            }
          }, 40);
        }
      }
    },
    updateData() {
      if (this.timer) {
        clearInterval(this.timer);
      }
      this.timer = setInterval(() => {
        this.faultCategoryList.forEach(function (item) {
          item.value += 1;
        });
        this.badCauseList.forEach(function (item) {
          item.value += 1;
        });
      }, 10000);
    },
