<template>
  <div class="threeModel">
    <div id="container"></div>
    <div id="tooltip">
      <div class="title">DIP 2-1涂覆线</div>
      <div class="progress">
        <p class="state">
          <span
            class="icon"
            :style="{ backgroundColor: dict_color[progress.state] }"
          ></span>
          {{ progress.state }}
        </p>
        <p class="value">
          <animate-number
            from="0"
            :key="progress.value"
            :to="progress.value"
            duration="2000"
            easing="easeOutQuad"
            :formatter="formatter"
          ></animate-number>
          %
        </p>
        <el-progress
          :percentage="progress.value"
          :show-text="false"
          :color="dict_color[progress.state]"
        ></el-progress>
      </div>
      <ul class="infoList">
        <li v-for="(item, index) in infoList" :key="index">
          <label>{{ item.label }}：</label>
          <span>{{ item.value }}</span>
        </li>
      </ul>
    </div>
    <ul
      id="labelList"
      :style="{
        color: dict_color[progress.state],
        borderColor: dict_color[progress.state],
      }"
    >
      <li v-for="(item, index) in labelList" :key="index">
        {{ item }}
      </li>
    </ul>
    <div class="tabAndState">
      <ul class="stateList">
        <li v-for="(item, index) in stateList" :key="index">
          {{ item }}
        </li>
      </ul>
      <ul class="typeList">
        <li
          v-for="(item, index) in typeList"
          :class="typeIndex == index ? 'active' : ''"
          @click="changeType(index)"
          :key="index"
        >
          {{ item }}
        </li>
      </ul>
    </div>
  </div>
</template>
<script>
import * as THREE from "three";
import { GLTFLoader } from "three/examples/jsm/loaders/GLTFLoader";
import { OrbitControls } from "three/examples/jsm/controls/OrbitControls.js";
import {
  CSS3DRenderer,
  CSS3DObject,
} from "three/examples/jsm/renderers/CSS3DRenderer.js";
import {
  CSS2DRenderer,
  CSS2DObject,
} from "three/examples/jsm/renderers/CSS2DRenderer.js";
export default {
  name: "ThreeModel",
  data() {
    return {
      stateList: ["运行", "维护", "停机"],
      typeList: [
        "DIP 1-1",
        "DIP 1-2",
        "DIP 1-3",
        "DIP 2-1",
        "DIP 2-2",
        "SMT 1#",
      ],
      typeIndex: 0,
      camera: null, //相机对象
      scene: null, //场景对象
      renderer: null, //渲染器对象
      mesh: null, //网格模型对象Mesh
      controls: null, //控件对象
      labelRenderer: null,
      labelRenderer2D: null,
      texture: null,
      labelList: [
        "目检桌",
        "接驳台",
        "涂敷",
        "接驳台",
        "UV固化",
        "接驳台",
        "目检桌",
      ],
      progress: {
        state: "运行中",
        value: 98.35,
      },
      progress1: {
        state: "运行中",
        value: 98.35,
      },
      progress2: {
        state: "维护中",
        value: 88.35,
      },
      progress3: {
        state: "停机中",
        value: 78.35,
      },
      dict_color: {
        运行中: "#32e5ad",
        维护中: "#fb8d1c",
        停机中: "#e9473a",
      },
      infoList: [
        {
          label: "线体状态",
          value: "运行",
        },
        {
          label: "在产物料",
          value: "北汽56S",
        },
        {
          label: "标准产能",
          value: "325/H",
        },
        {
          label: "实际产能",
          value: "325/H",
        },
        {
          label: "计划产量",
          value: "888",
        },
        {
          label: "实际产量",
          value: "568",
        },
      ],
    };
  },
  components: {},
  methods: {
    formatter: function (num) {
      return num.toFixed(2);
    },
    changeType(index) {
      this.typeIndex = index;
      if (index % 3 == 0) {
        this.progress = this.progress1;
      } else if (index % 3 == 1) {
        this.progress = this.progress2;
      } else {
        this.progress = this.progress3;
      }
    },
    init() {
      this.scene = new THREE.Scene();
      /**
       * 创建网格模型
       */
      let geometry = new THREE.BoxGeometry(640, 1, 70); //创建一个立方体几何对象Geometry
      let material = new THREE.MeshLambertMaterial({
        color: 0xffffff,
        transparent: true,
        opacity: 1,
      }); //材质对象Material 可以自定义颜色

      this.mesh = new THREE.Mesh(geometry, material); //网格模型对象Mesh
      this.mesh.position.set(0, -140, 0); //位置
      this.scene.add(this.mesh); //网格模型添加到场景中
      //   let axisHelper = new THREE.AxesHelper(500);
      //   this.scene.add(axisHelper); //辅助线
      /**
       * 光源设置
       */
      //点光源
      let point = new THREE.PointLight(0xffffff, 0.5);
      point.position.set(0, 200, 300); //点光源位置
      this.scene.add(point); //点光源添加到场景中
      //环境光
      let ambient = new THREE.AmbientLight(0xffffff, 0.3);
      this.scene.add(ambient);
      console.log(this.scene);
      /**
       * 相机设置
       */
      let container = document.getElementById("container");
      let width = container.clientWidth; //窗口宽度
      let height = container.clientHeight; //窗口高度
      let k = width / height; //窗口宽高比
      let s = 230; //三维场景显示范围控制系数，系数越大，显示的范围越大
      //创建相机对象
      this.camera = new THREE.OrthographicCamera(-s * k, s * k, s, -s, 1, 1000);
      this.camera.position.set(-100, 100, 500); //设置相机位置
      this.camera.lookAt(this.scene.position); //设置相机方向(指向的场景对象)
      /**
       * 创建渲染器对象
       */
      this.renderer = new THREE.WebGLRenderer({
        antialias: true,
        preserveDrawingBuffer: true,
      });
      this.renderer.setSize(width, height); //设置渲染区域尺寸
      this.renderer.setClearColor(0xffffff, 0); //设置背景颜色
      container.appendChild(this.renderer.domElement);
      /**
       * 创建3d文本渲染器对象
       */
      this.labelRenderer = new CSS3DRenderer();
      this.labelRenderer.setSize(width, height);
      this.labelRenderer.domElement.style.position = "absolute";
      this.labelRenderer.domElement.style.top = 0;
      container.appendChild(this.labelRenderer.domElement);
      /**
       * 创建2d文本渲染器对象
       */
      this.labelRenderer2D = new CSS2DRenderer();
      this.labelRenderer2D.setSize(width, height);
      this.labelRenderer2D.domElement.style.position = "absolute";
      this.labelRenderer2D.domElement.style.top = 0;
      container.appendChild(this.labelRenderer2D.domElement);

      //执行渲染操作   指定场景、相机作为参数
      this.renderer.render(this.scene, this.camera);
      // 创建控件对象
      this.controls = new OrbitControls(
        this.camera,
        this.labelRenderer2D.domElement
      );
      this.controls.enableZoom = false;
      // 监听控件操作
      this.controls.addEventListener("change", () => {
        this.renderer.render(this.scene, this.camera);
        this.labelRenderer.render(this.scene, this.camera);
        this.labelRenderer2D.render(this.scene, this.camera);
      });
    },
    // 外部模型加载函数
    loadGltf() {
      let loader = new GLTFLoader();
      loader.load("../model/cj.glb", (gltf) => {
        gltf.scene.position.set(16, -139, 140);
        this.scene.add(gltf.scene);
        this.renderer.render(this.scene, this.camera);
      });
    },
    // 添加提示框
    addTooltip() {
      let laberDiv = document.getElementById("tooltip");
      let pointLabel = new CSS2DObject(laberDiv);
      pointLabel.position.set(0, 120, 0);
      this.scene.add(pointLabel);
      this.labelRenderer2D.render(this.scene, this.camera);
    },
    // 添加机器名
    addLabel() {
      let laberDiv = document.getElementById("labelList");
      let pointLabel = new CSS3DObject(laberDiv);
      pointLabel.position.set(0, -150, 35);
      this.scene.add(pointLabel);
      this.labelRenderer.render(this.scene, this.camera);
    },
    // 添加围墙
    addWall() {
      var c = [
        -320,
        35, //顶点1坐标
        320,
        35, //顶点2坐标
        320,
        -35,
        -320,
        -35,
        -320,
        35,
      ];

      var geometry = new THREE.BufferGeometry(); //声明一个空几何体对象
      var posArr = [];
      var uvrr = [];

      var h = -40; //围墙拉伸高度
      for (var i = 0; i < c.length - 2; i += 2) {
        // 三角形1  三个顶点坐标
        posArr.push(
          c[i],
          c[i + 1],
          -140,
          c[i + 2],
          c[i + 3],
          -140,
          c[i + 2],
          c[i + 3],
          h
        );
        // 三角形2  三个顶点坐标
        posArr.push(
          c[i],
          c[i + 1],
          -140,
          c[i + 2],
          c[i + 3],
          h,
          c[i],
          c[i + 1],
          h
        );

        // 注意顺序问题，和顶点位置坐标对应
        uvrr.push(0, 0, 1, 0, 1, 1);
        uvrr.push(0, 0, 1, 1, 0, 1);
      }
      geometry.attributes.position = new THREE.BufferAttribute(
        new Float32Array(posArr),
        3
      );
      geometry.attributes.uv = new THREE.BufferAttribute(
        new Float32Array(uvrr),
        2
      );
      geometry.computeVertexNormals();

      this.mesh = new THREE.Mesh(geometry);
      this.texture = new THREE.TextureLoader().load(
        "../images/linearGradient.png"
      );
      this.mesh.material = new THREE.MeshLambertMaterial({
        color: this.dict_color[this.progress.state],
        map: this.texture,
        transparent: true,
        side: THREE.DoubleSide,
        depthTest: false,
      });
      this.mesh.position.set(0, 0, 0);
      this.mesh.rotation.x = -Math.PI * 0.5;
      this.scene.add(this.mesh);
    },
    // 事件会在窗口被调整大小时发生,重置渲染器输出画布canvas尺寸
    onWindowResize() {
      let container = document.getElementById("container");
      let width = container.clientWidth; //窗口宽度
      let height = container.clientHeight; //窗口高度
      this.renderer.setSize(width, height);
      this.labelRenderer.setSize(width, height);
      this.labelRenderer2D.setSize(width, height);
      let k = width / height; //窗口宽高比
      let s = 230; //三维场景显示范围控制系数，系数越大，显示的范围越大
      this.camera.left = -s * k;
      this.camera.right = s * k;
      this.camera.top = s;
      this.camera.bottom = -s;
      this.camera.updateProjectionMatrix();
      this.renderer.render(this.scene, this.camera);
      this.labelRenderer.render(this.scene, this.camera);
      this.labelRenderer2D.render(this.scene, this.camera);
    },
  },
  watch: {
    progress: {
      handler() {
        this.mesh.material = new THREE.MeshLambertMaterial({
          color: this.dict_color[this.progress.state],
          map: this.texture,
          transparent: true,
          side: THREE.DoubleSide,
          depthTest: false,
        });
        this.renderer.render(this.scene, this.camera);
      },
      deep: true,
    },
  },
  mounted() {
    this.progress = this.progress1;
    this.init();
    this.loadGltf();
    this.addWall();
    this.addTooltip();
    this.addLabel();
    window.addEventListener("resize", this.onWindowResize);
  },
  beforeDestroy() {
    window.removeEventListener("resize", this.onWindowResize);
  },
};
</script>
