<template>
  <div class="tableView">
    <el-table
      :data="dataT"
      ref="scroll_table"
      style="width: 100%"
      height="100%"
      @cell-mouse-enter="mouseEnter"
      @cell-mouse-leave="mouseLeave"
    >
      <el-table-column prop="id" label="编号" min-width="140px">
      </el-table-column>
      <el-table-column prop="name" label="名称" width="100px">
      </el-table-column>
      <el-table-column prop="type" label="设备类型" width="100px">
      </el-table-column>
      <el-table-column prop="state" label="状态" width="80px">
        <template slot-scope="scope">
          <span :class="addClass(scope.row.state)">{{ scope.row.state }}</span>
        </template>
      </el-table-column>
    </el-table>
  </div>
</template>
<script>
export default {
  name: "TableView",
  data() {
    return {
      autoPlay: true,
      dataT: this.tableData,
      timer: null,
    };
  },
  props: {
    tableData: {
      type: Array,
      required: true,
      default: () => [],
    },
  },
  components: {},
  mounted() {
    this.startMove();
  },

  methods: {
    addClass(i) {
      if (i === "待检查") {
        return "type1";
      } else if (i === "已超期") {
        return "type2";
      } else if (i === "已完成") {
        return "type3";
      } else if (i === "超期完成") {
        return "type4";
      }
    },
    // 鼠标进入
    mouseEnter() {
      this.autoPlay = false;
    },
    // 鼠标离开
    mouseLeave() {
      this.autoPlay = true;
    },
    startMove() {
      // 拿到表格挂载后的真实DOM
      const table = this.$refs.scroll_table;
      if (table) {
        // 拿到表格中承载数据的div元素
        const divData = table.bodyWrapper;
        if (divData) {
          if (this.timer) {
            clearInterval(this.timer);
          }
          // 拿到元素后，对元素进行定时增加距离顶部距离，实现滚动效果(此配置为每20毫秒移动1像素)
          this.timer = setInterval(() => {
            if (this.autoPlay) {
              // 元素自增距离顶部1像素
              if (divData.scrollTop >= 36) {
                const item = this.dataT.shift();
                this.dataT.push(item);
                divData.scrollTop -= 36;
              }
              divData.scrollTop += 1;
            }
          }, 40);
        }
      }
    },
  },
};
</script>
