<template>
  <section>
    <div class="wrap-card">
      <ul class="cards">
        <li
          v-for="(color, i) in bgColors"
          :key="i"
          :style="{ background: color }"
        >
          {{ color }}
        </li>
      </ul>
    </div>
  </section>
</template>

<script>
export default {
  data() {
    return {
      bgColors: ["#E65D6E", "#30B08F", "#4AB7BD", "#FEC171", "#1890ff"],
    };
  },
  created() {
    // 复制第一个数据到最后实现无缝轮播
    this.bgColors = this.bgColors.concat(this.bgColors.slice(0, 1));
  },
};
</script>

