<template>
  <div class="dateWeather">
    <div class="date">
      <p>{{ nowDate }}</p>
      <p>{{ nowTime }}</p>
    </div>
    <div class="weather">
      <p>14℃</p>
      <p>合肥</p>
    </div>
  </div>
</template>

<script>
export default {
  name: "DateWeather",
  data() {
    return {
      nowDate: "",
      nowTime: "",
    };
  },
  components: {},
  mounted() {
    // 时间
    this.timer = setInterval(() => {
      this.setNowTimes();
    }, 1000);
  },
  methods: {
    // 当前时间
    setNowTimes() {
      let myDate = new Date();
      let yy = String(myDate.getFullYear());
      let m = myDate.getMonth() + 1;
      let mm = String(myDate.getMonth() < 9 ? "0" + m : m);
      let dd = String(
        myDate.getDate() < 10 ? "0" + myDate.getDate() : myDate.getDate()
      );
      let hou = String(
        myDate.getHours() < 10 ? "0" + myDate.getHours() : myDate.getHours()
      );
      let min = String(
        myDate.getMinutes() < 10
          ? "0" + myDate.getMinutes()
          : myDate.getMinutes()
      );
      let sec = String(
        myDate.getSeconds() < 10
          ? "0" + myDate.getSeconds()
          : myDate.getSeconds()
      );
      this.nowDate = yy + "-" + mm + "-" + dd;
      this.nowTime = hou + ":" + min + ":" + sec;
    },
  },
};
</script>
